// Import necessary libraries
const Web3 = require('web3');
const { ethers } = require('ethers');

// Wallet configuration with private key
const privateKey = 'YOUR_PRIVATE_KEY';
const provider = new ethers.providers.JsonRpcProvider('YOUR_INFURA_ENDPOINT');
const wallet = new ethers.Wallet(privateKey, provider);

// Function to send ETH
async function sendETH(toAddress, amount) {
  const tx = {
    to: toAddress,
    value: ethers.utils.parseEther(amount),
  };
  const sendTx = await wallet.sendTransaction(tx);
  return sendTx.hash;
}

// Function to interact with smart contract
async function interactWithContract(contractAddress, abi, functionName, params) {
  const contract = new ethers.Contract(contractAddress, abi, wallet);
  const tx = await contract[functionName](...params);
  return tx.hash;
}